// n8n Code node (Run Once for All Items)
const items = $input.all();

return items.map(item => {
  const data = item.json;

  const userTotal = Number(data["希望者希望個数合計"] ?? 0);
  const hostTotal = Number(
    data["主催者希望数"] ?? data["主催者希望数量"] ?? 0
  );

  return {
    json: {
      ...data,
      管理IDごとの希望個数合計: userTotal + hostTotal
    }
  };
});

const items = $input.all();
const grouped = {};

for (const item of items) {
  const data = item.json;

  const managementId = data["管理ID"];
  const applicantManagementId = data["希望者管理ID"] ?? null;
  const wishedCount = Number(data["希望者希望個数"] ?? 0);
  const url = data["タイムスタンプ"];

  // Slack URL から ts を抽出
  // 例:
  // .../p1776389979316729 -> 1776389979.316729
  let ts = null;
  if (typeof url === "string") {
    const match = url.match(/p(\d{10})(\d{6})/);
    if (match) {
      ts = `${match[1]}.${match[2]}`;
    }
  }

  if (!grouped[managementId]) {
    grouped[managementId] = {
      管理ID: managementId,
      希望者希望個数合計: 0,
      希望者一覧: []
    };
  }

  grouped[managementId].希望者一覧.push({
    希望者管理ID: applicantManagementId,
    名前: data["希望者"],
    ユーザーID: data["ユーザーID"],
    希望数: wishedCount,
    タイムスタンプ: ts,
    元URL: url
  });

  grouped[managementId].希望者希望個数合計 += wishedCount;
}

// 希望者一覧をタイムスタンプ順に並べる
for (const group of Object.values(grouped)) {
  group.希望者一覧.sort((a, b) => {
    const ta = Number(a.タイムスタンプ ?? 0);
    const tb = Number(b.タイムスタンプ ?? 0);
    return ta - tb;
  });
}

return Object.values(grouped).map(group => ({
  json: group
}));

const items = $input.all();
const grouped = new Map();

for (const item of items) {
  const data = item.json;

  const managementId = data["管理ID"] ?? data["ID"] ?? null;
  const product = data["商品"] ?? {};
  const summary = data["まとめ"] ?? {};
  const host = data["主催者"] ?? {};
  const applicants = Array.isArray(data["希望者一覧"]) ? data["希望者一覧"] : [];
  const comms = data["通信"] ?? {};

  const price = Number(product["金額"] ?? 0);
  const quantity = Number(product["商品個数"] ?? 0);
  const hostWishedCount = Number(product["主催者希望数"] ?? 0);
  const unitPrice = Math.ceil(quantity > 0 ? price / quantity : 0);
  const hostPayment = hostWishedCount * unitPrice;

  if (!grouped.has(managementId)) {
    grouped.set(managementId, {
      管理ID: managementId,
      商品: {
        商品名: product["商品名"],
        URL: product["URL"],
        金額: product["金額"],
        商品個数: product["商品個数"],
        主催者希望数: hostWishedCount,
        商品単価: unitPrice
      },
      まとめ: {
        希望個数合計: 0,
        管理IDごとの希望個数合計: summary["管理IDごとの希望個数合計"] ?? 0
      },
      主催者: {
        名前: host["名前"],
        ユーザーID: host["ユーザーID"],
        PayPayID: host["PayPayID"],
        希望数: hostWishedCount,
        支払額: hostPayment
      },
      希望者一覧: [],
      通信: {
        スレッドタイムスタンプ: comms["スレッドタイムスタンプ"]
      }
    });
  }

  const group = grouped.get(managementId);

  for (const applicant of applicants) {
    const wishedCount = Number(applicant["希望数"] ?? applicant["希望個数"] ?? 0);
    const payment = wishedCount * unitPrice;
    const applicantUserId = applicant["ユーザーID"] ?? null;
    const applicantManagementId =
      applicant["希望者管理ID"] ??
      (managementId && applicantUserId ? `${managementId}${applicantUserId}` : null);

    group.希望者一覧.push({
      希望者管理ID: applicantManagementId,
      名前: applicant["名前"],
      ユーザーID: applicantUserId,
      希望数: wishedCount,
      支払額: payment,
      タイムスタンプ: applicant["タイムスタンプ"]
    });

    group.まとめ.希望個数合計 += wishedCount;
  }
}

for (const group of grouped.values()) {
  group.希望者一覧.sort((a, b) => Number(a.タイムスタンプ ?? 0) - Number(b.タイムスタンプ ?? 0));
}

return Array.from(grouped.values()).map(group => ({
  json: group
}));

