// Loop over input items and add a new field called 'myNewField' to the JSON of each one
function formatTimestamp(url) {
  const match = url.match(/p(\d+)/);
  if (!match) return null;

  let num = match[1];

  // 下16桁を取得
  num = num.slice(-16);

  // 下6桁を小数点に
  const integerPart = num.slice(0, -6);
  const decimalPart = num.slice(-6);

  return `${integerPart}.${decimalPart}`;
}

return items.map(item => {
  const data = item.json;

  return {
    json: {
      商品名: data.商品名,
      URL: data.URL,
      金額: data.金額,
      商品個数: data.商品個数,
      主催者希望数量: data.主催者希望数量,
      主催者: data.主催者,
      PayPayID: data.PayPayID,
      スレッドタイムスタンプ: formatTimestamp(data.タイムスタンプ),
      管理ID: data.管理ID,
      ホストユーザーID: data.ユーザーID
    }
