const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const product = data["商品"] ?? {};
  const summary = data["まとめ"] ?? {};
  const host = data["主催者"] ?? {};
  const applicants = data["希望者一覧"] ?? [];
  const comms = data["通信"] ?? {};

  const hostUserId = host["ユーザーID"] ?? null;
  const hostName = host["名前"] ?? null;
  const hostWantedCount = Number(host["希望数"] ?? product["主催者希望数"] ?? 0);
  const hostPayment = Number(host["支払額"] ?? 0);

  const commonFields = {
    管理ID: data["管理ID"],
    商品名: product["商品名"] ?? null,
    商品URL: product["URL"] ?? null,
    商品単価: Number(product["商品単価"] ?? 0),
    商品個数: Number(product["商品個数"] ?? 0),
    主催者希望数: hostWantedCount,
    主催者支払額: hostPayment,
    希望個数合計: Number(summary["希望個数合計"] ?? 0),
    管理IDごとの希望個数合計: Number(summary["管理IDごとの希望個数合計"] ?? 0),
    主催者名: hostName,
    主催者ユーザーID: hostUserId,
    PayPayID: host["PayPayID"] ?? null,
    スレッドタイムスタンプ: comms["スレッドタイムスタンプ"] ?? null,
  };

  // 主催者向け row
  if (hostUserId) {
    results.push({
      json: {
        送信キー: `${data["管理ID"]}_${hostUserId}_host`,
        送信種別: "主催者",
        宛先ユーザーID: hostUserId,
        宛先名: hostName,
        希望者管理ID: null,
        希望者名: null,
        希望者ユーザーID: null,
        希望者希望数: null,
        希望者支払額: null,
        希望者タイムスタンプ: null,
        ...commonFields,
      }
    });
  }

  // 希望者向け row
  for (const person of applicants) {
    const userId = person["ユーザーID"];
    if (!userId) continue;

    const applicantManagementId =
      person["希望者管理ID"] ??
      (data["管理ID"] && userId ? `${data["管理ID"]}${userId}` : null);

    results.push({
      json: {
        送信キー: `${data["管理ID"]}_${userId}_applicant`,
        送信種別: "希望者",
        宛先ユーザーID: userId,
        宛先名: person["名前"] ?? null,
        希望者管理ID: applicantManagementId,
        希望者名: person["名前"] ?? null,
        希望者ユーザーID: userId,
        希望者希望数: Number(person["希望数"] ?? 0),
        希望者支払額: Number(person["支払額"] ?? 0),
        希望者タイムスタンプ: person["タイムスタンプ"] ?? null,
        ...commonFields,
      }
    });
  }
}

return results;

