const rows = $input.all().map(item => item.json);

if (rows.length === 0) {
  return [];
}

// payment done の行だけ対象にする
const paidRows = rows.filter(row =>
  String(row["status"] ?? "").trim() === "payment done"
);

if (paidRows.length === 0) {
  return [];
}

// payment done になった各案件をユニーク化
const managementMap = new Map();

for (const row of paidRows) {
  const applicantManagementId = row["希望者管理ID"] ?? null;
  const applicantUserId = row["希望者ユーザーID"] ?? row["ユーザーID"] ?? null;

  if (!applicantManagementId || !applicantUserId) continue;
  if (!String(applicantManagementId).endsWith(String(applicantUserId))) continue;

  const managementId = String(applicantManagementId).slice(0, -String(applicantUserId).length);

  if (!managementMap.has(managementId)) {
    managementMap.set(managementId, []);
  }

  managementMap.get(managementId).push(row);
}

const results = [];

for (const [managementId] of managementMap.entries()) {
  const sameManagementRows = rows.filter(row => {
    const rowApplicantManagementId = row["希望者管理ID"] ?? null;
    const rowApplicantUserId = row["希望者ユーザーID"] ?? row["ユーザーID"] ?? null;

    if (!rowApplicantManagementId || !rowApplicantUserId) return false;
    if (!String(rowApplicantManagementId).endsWith(String(rowApplicantUserId))) return false;

    const rowManagementId = String(rowApplicantManagementId).slice(0, -String(rowApplicantUserId).length);
    return rowManagementId === managementId;
  });

  if (sameManagementRows.length === 0) continue;

  const allDone = sameManagementRows.every(row =>
    String(row["status"] ?? "").trim() === "payment done"
  );

  if (!allDone) continue;

  results.push({
    json: {
      管理ID: managementId,
      希望者人数: sameManagementRows.length,
      allDone: true
    }
  });
}

return results;

